sql:
SELECT AVG(query_duration) 
FROM query_runs 
WHERE query_status = 'completed';

SELECT query_number, COUNT(run_id) AS 'Number of Runs'
FROM query_runs
GROUP BY query_number;

SELECT run_id 
FROM query_runs 
WHERE gt_value > (SELECT AVG(gt_value) FROM query_runs);

SELECT u.user_name, q.query_sql
FROM queries q
JOIN users u ON q.query_author = u.user_id;

SELECT *
FROM query_runs
ORDER BY run_date DESC;

SELECT run_id, AVG(query_duration) AS average_duration
FROM query_runs
GROUP BY run_id;

SELECT interval_source
FROM confidence_intervals
WHERE run_id = 1;

external_knowledge:
- 'customer' category refers to queries related to customer data;
- 'average runtime > 30' means the average time taken for a query to run is more than half a minute;
- Queries are ordered by their latest occurrence ('DESC' referring to descending order based on 'query_number').

sql:
SELECT version_number, version_sql, version_date, version_description, version_last_modified, version_last_modified_by
FROM query_versions
WHERE query_id = 1;

SELECT COUNT(DISTINCT queries.query_id) AS TotalUniqueQueries
FROM query_runs
INNER JOIN queries ON query_runs.query_number = queries.query_number;

SELECT query_number, query_status
FROM query_runs
WHERE query_number = 1 AND run_date = '2023-01-01';
